import React from 'react';
import Layout from '../layout/Layout';
import './Resources.css'

function Resources({ loaded, showContact, setShowContact, showMenu, setShowMenu }) {
  return (
    <Layout loaded={loaded} showContact={showContact} setShowContact={setShowContact} showMenu={showMenu} setShowMenu={setShowMenu}>
      <h1 className='resources title'>Complementary Free Resources</h1>

      <h2 className='resources subtitle'>4 Common Orphan Drug Market Access Mistakes That Waste Your Time and Money</h2>

      <h3 className='resources subtitle'>
        1. Hiring a single consultant will solve the problem
      </h3>
      <p className='resources text'>
        <i>Nothing more wrong than this!</i> A single consultant will never be able to cover the multiple interfaces and requirements of successful local market access.
      </p>

      <h3 className='resources subtitle'>2. Reimbursement prices are very low.</h3>
      <p className='resources text'>
        <i>Wrong again!</i> It is true that fewer products are reimbursed, but the ones, which are paid for, are similarly priced as in Western EU countries. This underlines the importance of professional planning and preparation only possible with profound market access experience and local knowledge.</p>
      
      <h3 className='resources subtitle'>3. Reimbursement granted will stay on forever</h3>
      <p className='resources text'>
        <i>And wrong again!</i> In the CEE region reimbursement might need to be renegotiated on a yearly basis in well prepared discussion rounds with reimbursement authorities.
      </p>

      <h3 className='resources subtitle'>4. Getting the EU launch sequence wrong!</h3>
      <p className='resources text'>
        We provide you with crucial information about expected pricings and the resulting launch plan to prevent later disappointment and losses.
      </p>

      <h2 className='resources subtitle'>5 Surefire Ways To Achieve Long Lasting Orphan Drug Market Access and Sales Success in Eastern European EU Countries</h2>

      <h3 className='resources subtitle'>1. Get a local partner company with a strong track record!</h3>
      <p className='resources text'>They should be able to cover the full spectrum of market access including marketing and sales.</p>
      
      <h3 className='resources subtitle'>2. Don’t relay on extrapolations for treatable patients!</h3>
      <p className='resources text'>Have a team getting out there doing the real field work.</p>

      <h3 className='resources subtitle'>3. Keep prices up across the region!</h3>
      <p className='resources text'>Europe is a fragmented place and authorities tend to watch each other and tend to communicate. A sound pricing strategy makes or brakes the project.</p>

      <h3 className='resources subtitle'>4. Leverage the power and influence of patient organisations!</h3>
      <p className='resources text'>A well-organized patient organization helps to advance reimbursement decisions in a big way. Talk to them, engage them and help them with useful information.</p>

      <h3 className='resources subtitle'>5. Focus on patient finding activities!</h3>
      <p className='resources text'>This is key to grow your business and only a partner with an excellent network to the physicians can succeed.</p>

      <h2 className='resources subtitle'>4 Most Compelling Reasons Why To Work with a Local Orphan Drug Market Access, Pricing and Sales Partner in Eastern Europe (CEE)</h2>

      <h3 className='resources subtitle'>1. Language still a significant barrier!</h3>
      <ul className='resources list list1'><li>Significant time can be lost and process lengthened due to miscommunication. Relevant parts of reimbursement process change often rapidly and are not translated immediately or at all.</li></ul>

      <h3 className='resources subtitle'>2. Long-term control of payment streams is key!</h3>
      <ul className='resources list list2'><li>A local partner makes sure that you receive payments in time.</li></ul>

      <h3 className='resources subtitle'>3. No upfront investment in infrastructure needed!</h3>
      <ul className='resources list list3'><li>For rare and especially ultra rare diseases it is often not economical to set up a full infrastructure. A local company has it all and on top of it an excellent living network to doctors, KOLs, patient organizations and authorities.</li></ul>

      <h3 className='resources subtitle'>4. Health Technology Assessment (HTA)</h3>
      <ul className='resources list list4'>
        <li>Added clinical benefit evaluation (similar to Western EU countries)</li>
        <li>Budget impact analysis (can differ significantly)</li>
        <li>Cost-effectiveness analysis (can differ significantly)</li>
      </ul>
    </Layout>
  )
}

export default Resources