import Header from './../header/Header';
import Contact from './../contact/Contact';
import Footer from './../footer/Footer';

function Layout({children, loaded, showContact, setShowContact, showMenu, setShowMenu}) {
  return (
    <>
      <main className={loaded ? 'loaded' : null}>
        <Header loaded={loaded} showMenu={showMenu} setShowMenu={setShowMenu}/>
        {loaded && 
          <div className='content'>
                {children}
              <Contact showContact={showContact} setShowContact={setShowContact}/>
            </div>
        }
        </main>
      <Footer loaded={loaded}/>
    </>
  )
}

export default Layout